scripts.content:
extends Node

## Signals for UI integration
signal item_added(slot: int, item: Dictionary)
signal item_removed(slot: int, item: Dictionary)
signal item_moved(from_slot: int, to_slot: int)
signal equipment_changed(slot_type: String, item: Dictionary)
signal weight_changed(current: float, max_weight: float)

enum ItemCategory { WEAPON, ARMOR, CONSUMABLE, QUEST, MATERIAL, MISC }
enum EquipSlot { MAIN_HAND, OFF_HAND, HEAD, CHEST, LEGS, FEET, RING_1, RING_2, NECK }

const DEFAULT_STACK_LIMIT := {{default_stack_limit}}

var _slots: Array[Dictionary] = []
var _equipment: Dictionary = {}
var _current_weight: float = 0.0

func _ready():
	for i in range({{inventory_capacity}}):
		_slots.append({"empty": true, "item_id": "", "count": 0, "data": {}})

func add_item(item_id: String, count: int = 1, data: Dictionary = {}) -> int:
	"""Try to add an item. Returns count successfully added."""
	var item_def := ItemDatabase.get_item(item_id)
	if item_def.is_empty():
		push_error("Unknown item: %s" % item_id)
		return 0

	var stack_limit := item_def.get("stack_limit", DEFAULT_STACK_LIMIT)
	var remaining := count
	var added := 0

	# First, try to stack onto existing partial stacks
	for i in range(_slots.size()):
		if remaining <= 0:
			break
		if not _slots[i].empty and _slots[i].item_id == item_id:
			var space := stack_limit - _slots[i].count
			if space > 0:
				var to_add := min(remaining, space)
				_slots[i].count += to_add
				remaining -= to_add
				added += to_add

	# Then, fill empty slots
	while remaining > 0:
		var empty_idx := _find_empty_slot()
		if empty_idx == -1:
			break
		var to_add := min(remaining, stack_limit)
		_slots[empty_idx] = {"empty": false, "item_id": item_id, "count": to_add, "data": data}
		remaining -= to_add
		added += to_add
		item_added.emit(empty_idx, _slots[empty_idx])

	_update_weight()
	return added

func remove_item(slot: int, count: int = 1) -> int:
	"""Remove items from a slot. Returns count actually removed."""
	if slot < 0 or slot >= _slots.size() or _slots[slot].empty:
		return 0

	var removed := min(count, _slots[slot].count)
	_slots[slot].count -= removed
	if _slots[slot].count <= 0:
		var old_item := _slots[slot]
		_slots[slot] = {"empty": true, "item_id": "", "count": 0, "data": {}}
		item_removed.emit(slot, old_item)

	_update_weight()
	return removed

func move_item(from_slot: int, to_slot: int) -> bool:
	"""Move or swap items between slots."""
	if from_slot < 0 or from_slot >= _slots.size() or _slots[from_slot].empty:
		return false
	if to_slot < 0 or to_slot >= _slots.size():
		return false

	# Stack if same item
	if not _slots[to_slot].empty and _slots[to_slot].item_id == _slots[from_slot].item_id:
		var item_def := ItemDatabase.get_item(_slots[from_slot].item_id)
		var limit := item_def.get("stack_limit", DEFAULT_STACK_LIMIT)
		var space := limit - _slots[to_slot].count
		if space > 0:
			var to_move := min(_slots[from_slot].count, space)
			_slots[to_slot].count += to_move
			remove_item(from_slot, to_move)
			item_moved.emit(from_slot, to_slot)
			return true

	var temp := _slots[to_slot]
	_slots[to_slot] = _slots[from_slot]
	_slots[from_slot] = temp
	item_moved.emit(from_slot, to_slot)
	return true

func equip_item(slot: int, equip_slot: String) -> bool:
	"""Equip an item from inventory to an equipment slot."""
	if slot < 0 or slot >= _slots.size() or _slots[slot].empty:
		return false

	var item := _slots[slot]
	var item_def := ItemDatabase.get_item(item.item_id)
	if item_def.get("equip_slot", "") != equip_slot:
		return false

	# Unequip existing item first
	if _equipment.has(equip_slot):
		var old := _equipment[equip_slot]
		add_item(old.item_id, old.count, old.data)

	_equipment[equip_slot] = item.duplicate(true)
	remove_item(slot, 1)
	equipment_changed.emit(equip_slot, _equipment[equip_slot])
	_update_weight()
	return true

func unequip_item(equip_slot: String) -> bool:
	"""Unequip an item back to inventory."""
	if not _equipment.has(equip_slot):
		return false

	var item := _equipment[equip_slot]
	var added := add_item(item.item_id, item.count, item.data)
	if added > 0:
		_equipment.erase(equip_slot)
		equipment_changed.emit(equip_slot, {})
		_update_weight()
		return true
	return false

func get_slot(slot: int) -> Dictionary:
	if slot >= 0 and slot < _slots.size():
		return _slots[slot]
	return {}

func get_all_items() -> Array[Dictionary]:
	var items: Array[Dictionary] = []
	for s in _slots:
		if not s.empty:
			items.append(s.duplicate())
	return items

func get_current_weight() -> float:
	return _current_weight

func get_weight_ratio() -> float:
	var max_w = float({{max_weight}})
	if max_w <= 0:
		return 0.0
	return _current_weight / max_w

func has_item(item_id: String, count: int = 1) -> bool:
	var found := 0
	for s in _slots:
		if not s.empty and s.item_id == item_id:
			found += s.count
		if found >= count:
			return true
	return false

func count_item(item_id: String) -> int:
	var total := 0
	for s in _slots:
		if not s.empty and s.item_id == item_id:
			total += s.count
	for eq in _equipment.values():
		if eq.item_id == item_id:
			total += eq.count
	return total

func can_carry(item_id: String, count: int = 1) -> bool:
	var max_w = float({{max_weight}})
	if {{enable_weight_system}} and max_w > 0:
		var item_def := ItemDatabase.get_item(item_id)
		var weight := item_def.get("weight", 0.0) * float(count)
		if _current_weight + weight > max_w:
			return false
	return _find_empty_slot() != -1 or _can_stack(item_id, count)

func serialize() -> Dictionary:
	return {
		"slots": _slots.duplicate(true),
		"equipment": _equipment.duplicate(true),
	}

func deserialize(data: Dictionary) -> void:
	_slots = data.get("slots", [])
	_equipment = data.get("equipment", {})
	_update_weight()

func _find_empty_slot() -> int:
	for i in range(_slots.size()):
		if _slots[i].empty:
			return i
	return -1

func _can_stack(item_id: String, count: int) -> bool:
	var item_def := ItemDatabase.get_item(item_id)
	if item_def.is_empty():
		return false
	var limit := item_def.get("stack_limit", DEFAULT_STACK_LIMIT)
	var room := 0
	for s in _slots:
		if not s.empty and s.item_id == item_id and s.count < limit:
			room += limit - s.count
	return room >= count

func _update_weight() -> void:
	if not {{enable_weight_system}}:
		return
	_current_weight = 0.0
	for s in _slots:
		if not s.empty:
			var item_def := ItemDatabase.get_item(s.item_id)
			_current_weight += item_def.get("weight", 0.0) * float(s.count)
	for eq in _equipment.values():
		var item_def := ItemDatabase.get_item(eq.item_id)
		_current_weight += item_def.get("weight", 0.0) * float(eq.count)
	weight_changed.emit(_current_weight, float({{max_weight}}))
